referenceSolutions:
.scroll-demo {
  height: 200vh;
  padding: 20px;
}
.scroll-section {
  margin-top: 50vh;
}
.progress-bar {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 4px;
  background-color: rgb(233, 236, 239);
  z-index: 100;
}
.progress-fill {
  height: 100%;
  background-color: rgb(0, 123, 255);
  width: 0%;
  animation: grow-progress linear;
  animation-timeline: scroll();
}
@keyframes grow-progress {
  to { width: 100%; }
}
.reveal-heading,
.reveal-text {
  opacity: 0;
  transform: translateY(20px);
  animation: reveal linear both;
  animation-timeline: view();
  animation-range: entry 0% entry 100%;
}
@keyframes reveal {
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.scroll-demo {
  height: 200vh;
  padding: 20px;
}
.scroll-section {
  margin-top: 50vh;
}
.progress-bar {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  height: 4px;
  background: #e9ecef;
  z-index: 100;
}
.progress-fill {
  height: 100%;
  background: #007bff;
  animation: fill-bar linear;
  animation-timeline: scroll();
  transform-origin: left;
  scale: 0 1;
}
@keyframes fill-bar {
  to { scale: 1 1; }
}
.reveal-heading,
.reveal-text {
  opacity: 0;
  animation: fade-in linear both;
  animation-timeline: view();
  animation-range: entry;
}
@keyframes fade-in {
  to { opacity: 1; }
}

